module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output reg wfull,
    output reg rempty,
    output reg [WIDTH-1:0]	rdata
);

reg [WIDTH-1:0] ram [DEPTH-1:0];
reg [ADDR_WIDTH-1:0] wptr, rptr;
wire [ADDR_WIDTH-1:0] waddr, raddr;

always @(posedge wclk) begin
    if (winc && !wfull) begin
        ram[waddr] <= wdata;
        wptr <= wptr + 1'b1;
    end
end

always @(posedge rclk) begin
    if (rinc && !rempty) begin
        rdata <= ram[raddr];
        rptr <= rptr + 1'b1;
    end
end

reg wempty, rfull;
wire wptr_gray, rptr_gray;

assign wptr_gray = wptr ^ (wptr >> 1);
assign rptr_gray = rptr ^ (rptr >> 1);

always @(*) begin
    wempty = (wptr_gray == rptr_gray) && !winc;
    rfull = (wptr_gray == rptr_gray) && !rinc;
end

reg [ADDR_WIDTH-1:0] wptr_sync, rptr_sync;

always @(posedge rclk) begin
    wptr_sync <= {wptr_sync[ADDR_WIDTH-2:0], wptr_gray};
end

always @(posedge wclk) begin
    rptr_sync <= {rptr_sync[ADDR_WIDTH-2:0], rptr_gray};
end

always @(*) begin
    wfull = rptr_sync == wptr;
    rempty = wempty;
end

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
